"""
tool_format_comparison.py — illustrates the tool-calling wire format
differences between GPT and Claude families.

Run with:
  pip install anthropic openai
"""

import json

# ── GPT (OpenAI) tool definition ──────────────────────────────────────────
GPT_TOOL_DEF = {
    "type": "function",
    "function": {
        "name": "search_docs",
        "description": "Search the documentation index for a query.",
        "parameters": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search query"},
                "top_k": {"type": "integer", "description": "Number of results", "default": 5},
            },
            "required": ["query"],
        },
    },
}

# ── Claude (Anthropic) tool definition ────────────────────────────────────
CLAUDE_TOOL_DEF = {
    "name": "search_docs",
    "description": "Search the documentation index for a query.",
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {"type": "string", "description": "Search query"},
            "top_k": {"type": "integer", "description": "Number of results"},
        },
        "required": ["query"],
    },
}

# ── GPT response when model calls the tool ────────────────────────────────
GPT_TOOL_CALL_RESPONSE = {
    "role": "assistant",
    "content": None,
    "tool_calls": [
        {
            "id": "call_abc123",
            "type": "function",
            "function": {
                "name": "search_docs",
                "arguments": json.dumps({"query": "context window", "top_k": 3}),
            },
        }
    ],
}

# ── Claude response when model calls the tool ─────────────────────────────
CLAUDE_TOOL_USE_RESPONSE = {
    "role": "assistant",
    "content": [
        {
            "type": "tool_use",
            "id": "toolu_abc123",
            "name": "search_docs",
            "input": {"query": "context window", "top_k": 3},
        }
    ],
}

print("GPT tool call args (string):")
print(GPT_TOOL_CALL_RESPONSE["tool_calls"][0]["function"]["arguments"])
# → Must JSON-parse this string before using

print("\nClaude tool input (already dict):")
print(CLAUDE_TOOL_USE_RESPONSE["content"][0]["input"])
# → No JSON parsing needed; already a Python dict

// provider_adapter.js — a thin adapter layer that normalises
// tool-call results from both GPT and Claude families into a
// single canonical format your agent can consume.

/**
 * @typedef {{ id: string, name: string, args: object }} ToolCall
 */

/**
 * Extract tool calls from a GPT-family chat completion response.
 * @param {import("openai").ChatCompletion} response
 * @returns {ToolCall[]}
 */
function extractToolCallsGPT(response) {
  const msg = response.choices[0].message;
  if (!msg.tool_calls) return [];
  return msg.tool_calls.map((tc) => ({
    id: tc.id,
    name: tc.function.name,
    args: JSON.parse(tc.function.arguments), // GPT returns args as JSON string
  }));
}

/**
 * Extract tool calls from a Claude-family Messages response.
 * @param {import("@anthropic-ai/sdk").Message} response
 * @returns {ToolCall[]}
 */
function extractToolCallsClaude(response) {
  return response.content
    .filter((block) => block.type === "tool_use")
    .map((block) => ({
      id: block.id,
      name: block.name,
      args: block.input, // Claude returns args already parsed
    }));
}

/**
 * Unified extractor — detects family from response shape.
 * @param {object} response
 * @returns {ToolCall[]}
 */
function extractToolCalls(response) {
  if (response.choices) return extractToolCallsGPT(response);
  if (response.content)  return extractToolCallsClaude(response);
  throw new Error(`Unrecognised response shape: ${JSON.stringify(Object.keys(response))}`);
}

// Demo (no real API call)
const mockGPTResponse = {
  choices: [{
    message: {
      role: "assistant",
      content: null,
      tool_calls: [{
        id: "call_001",
        type: "function",
        function: { name: "get_weather", arguments: '{"location":"London"}' },
      }],
    },
  }],
};

const mockClaudeResponse = {
  content: [{
    type: "tool_use",
    id: "toolu_001",
    name: "get_weather",
    input: { location: "London" },
  }],
};

console.log("GPT tools:   ", extractToolCalls(mockGPTResponse));
console.log("Claude tools:", extractToolCalls(mockClaudeResponse));
// Both print: [{ id: '...', name: 'get_weather', args: { location: 'London' } }]
